[Form]
public class ETGCustTransaction extends FormRun
{
    QueryBuildRange closed;

}

/// <summary>
///
/// </summary>
public void executeQuery()
{
    TransDate fromDate, toDate;
    TransDate emptyFromDate, emptyToDate;
    emptyFromDate = dateNull();
    emptyToDate = dateNull();
    fromDate    = 01\01\2012;
    toDate = today();

    if(ETGOpenDate.value() == NoYes::Yes)
    {
        closed.value(SysQuery::valueEmptyString());
        //closed.value(SysQuery::range(fromDate, toDate));
    }
    else
    {
        closed.value(SysQuery::range(emptyFromDate, emptyToDate));
    } 

    super();
}

/// <summary>
///
/// </summary>
public void init()
{
    super();

    closed = this.query().dataSourceNo(1).addRange(fieldNum(CustTrans, Closed));
}
